package ccxtpro
import ccxt "github.com/ccxt/ccxt/go/v4"
type Aftermath struct {
   *AftermathCore
   Core *AftermathCore
   exchangeTyped *ccxt.Aftermath
}

func NewAftermath(userConfig map[string]interface{}) *Aftermath {
   p := NewAftermathCore()
   p.Init(userConfig)
   return &Aftermath{
       AftermathCore: p,
       Core:  p,
       exchangeTyped: ccxt.NewAftermathFromCore(p.base),
   }
}


